#include <bits/stdc++.h>
using namespace std;
int main(){
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    int n; long long K; cin >> n >> K;
    unordered_map<long long,long long> cnt;
    long long ans = 0;
    for (int i = 0; i < n; i++){
        long long x; cin >> x;
        ans += cnt[K - x];
        cnt[x]++;
    }
    cout << ans << '\n';
}
